#!/bin/sh
# Statusline with theme support and configurable widgets
# Widgets: model, bar, ctx, tokens, cost, duration, lines, alert, git, project, version, vim, rate5h, rate7d, rate
# Themes: ansi-default, catppuccin-mocha, dracula, nord, none
# Config: ~/.claude/statusline-widgets.conf (generated by configure.sh)
# Set CLAUDE_STATUSLINE_THEME to choose theme. Set NO_COLOR=1 to disable colors.

VERSION="2.1.0"
if [ "${1:-}" = "--version" ]; then echo "$VERSION"; exit 0; fi

input=$(cat)

# ── Resolve Claude process PID ──────────────────────────────────────────────
_claude_pid="$PPID"
_parent=$(ps -o ppid= -p "$_claude_pid" 2>/dev/null | tr -d ' ')
if [ -n "$_parent" ]; then
    _pcomm=$(ps -o comm= -p "$_parent" 2>/dev/null | tr -d ' ')
    if [ "$_pcomm" = "claude" ]; then
        _claude_pid="$_parent"
    fi
fi

# ── Theme Selection ──────────────────────────────────────────────────────────
if [ -n "${NO_COLOR:-}" ]; then
    _theme="none"
else
    _theme="${CLAUDE_STATUSLINE_THEME:-ansi-default}"
fi

# ── Theme Definitions (12 semantic color tokens) ─────────────────────────────
case "$_theme" in
    catppuccin-mocha)
        C_MODEL='\033[38;2;203;166;247m'    # Mauve
        C_BAR_FILL='\033[38;2;166;227;161m' # Green
        C_BAR_EMPTY='\033[38;2;88;91;112m'  # Overlay0
        C_CTX_OK='\033[38;2;166;227;161m'   # Green
        C_CTX_WARN='\033[38;2;249;226;175m' # Yellow
        C_CTX_BAD='\033[38;2;243;139;168m'  # Red
        C_TOKENS='\033[38;2;137;220;235m'   # Teal
        C_COST='\033[38;2;250;179;135m'     # Peach
        C_ALERT='\033[1;38;2;243;139;168m'  # Bold Red
        C_BRANCH='\033[38;2;116;199;236m'   # Blue
        C_PROJECT='\033[38;2;166;227;161m'  # Green
        C_SEP='\033[38;2;88;91;112m'        # Overlay0
        ;;
    dracula)
        C_MODEL='\033[38;2;189;147;249m'    # Purple
        C_BAR_FILL='\033[38;2;80;250;123m'  # Green
        C_BAR_EMPTY='\033[38;2;98;114;164m' # Comment
        C_CTX_OK='\033[38;2;80;250;123m'    # Green
        C_CTX_WARN='\033[38;2;241;250;140m' # Yellow
        C_CTX_BAD='\033[38;2;255;85;85m'    # Red
        C_TOKENS='\033[38;2;139;233;253m'   # Cyan
        C_COST='\033[38;2;255;184;108m'     # Orange
        C_ALERT='\033[1;38;2;255;85;85m'    # Bold Red
        C_BRANCH='\033[38;2;139;233;253m'   # Cyan
        C_PROJECT='\033[38;2;80;250;123m'   # Green
        C_SEP='\033[38;2;98;114;164m'       # Comment
        ;;
    nord)
        C_MODEL='\033[38;2;180;142;173m'    # Nord15 purple
        C_BAR_FILL='\033[38;2;163;190;140m' # Nord14 green
        C_BAR_EMPTY='\033[38;2;76;86;106m'  # Nord3
        C_CTX_OK='\033[38;2;163;190;140m'   # Nord14 green
        C_CTX_WARN='\033[38;2;235;203;139m' # Nord13 yellow
        C_CTX_BAD='\033[38;2;191;97;106m'   # Nord11 red
        C_TOKENS='\033[38;2;136;192;208m'   # Nord8 cyan
        C_COST='\033[38;2;208;135;112m'     # Nord12 orange
        C_ALERT='\033[1;38;2;191;97;106m'   # Bold Nord11
        C_BRANCH='\033[38;2;129;161;193m'   # Nord9 blue
        C_PROJECT='\033[38;2;163;190;140m'  # Nord14 green
        C_SEP='\033[38;2;76;86;106m'        # Nord3
        ;;
    none)
        C_MODEL='' C_BAR_FILL='' C_BAR_EMPTY=''
        C_CTX_OK='' C_CTX_WARN='' C_CTX_BAD=''
        C_TOKENS='' C_COST='' C_ALERT=''
        C_BRANCH='' C_PROJECT='' C_SEP=''
        ;;
    *) # ansi-default
        C_MODEL='\033[35m'      # Purple
        C_BAR_FILL='\033[32m'   # Green
        C_BAR_EMPTY='\033[90m'  # Dark gray
        C_CTX_OK='\033[33m'     # Yellow
        C_CTX_WARN='\033[33m'   # Yellow
        C_CTX_BAD='\033[31m'    # Red
        C_TOKENS='\033[36m'     # Cyan
        C_COST='\033[33m'       # Yellow
        C_ALERT='\033[1;31m'    # Bold red
        C_BRANCH='\033[34m'     # Blue
        C_PROJECT='\033[32m'    # Green
        C_SEP='\033[2;37m'      # Dim gray
        ;;
esac

if [ "$_theme" = "none" ]; then
    C_RESET=''
else
    C_RESET='\033[0m'
fi

if [ "$_theme" = "none" ]; then
    SEP=' | '
else
    SEP=" ${C_SEP}│${C_RESET} "
fi

# ── Load widget config ──────────────────────────────────────────────────────
_conf="${CLAUDE_STATUSLINE_WIDGETS_CONF:-$HOME/.claude/statusline-widgets.conf}"
_widgets_l1=""
_widgets_l2=""

if [ -f "$_conf" ]; then
    while IFS= read -r _line || [ -n "$_line" ]; do
        case "$_line" in \#*|"") continue ;; esac
        _wname="${_line%% *}"
        _wline="${_line##* }"
        case "$_wline" in [12]) ;; *) _wline=1 ;; esac
        if [ "$_wline" = "2" ]; then
            _widgets_l2="$_widgets_l2 $_wname"
        else
            _widgets_l1="$_widgets_l1 $_wname"
        fi
    done < "$_conf"
else
    # Default layout (backward compatible)
    _widgets_l1=" model bar ctx tokens cost alert git project"
    _widgets_l2=""
fi

# ── Parse JSON input (single jq call) ───────────────────────────────────────
_now=$(date +%s)

_parsed=$(printf '%s' "$input" | jq --argjson epoch "$_now" -r '
def resets_min: . // "" | if . == "" then -1 elif type == "number" then ((. - $epoch) / 60 | floor) elif type == "string" then (gsub("\\+00:00$";"Z") | gsub("\\.[0-9]+Z$";"Z") | try fromdate catch -1) | if . == -1 then -1 else (. - $epoch) / 60 | floor end else -1 end;
def pct_or_neg1: . // -1 | if type == "number" then . elif type == "string" then (tonumber? // -1) else -1 end;
[
    (.model.display_name // "Unknown Model"),
    (.context_window.used_percentage // ""),
    (.context_window.total_input_tokens // 0 | tostring),
    (.context_window.total_output_tokens // 0 | tostring),
    (.cost.total_cost_usd // 0 | tostring),
    (.exceeds_200k_tokens // false | tostring),
    (.workspace.project_dir // .cwd // ""),
    (.cost.total_duration_ms // 0 | tostring),
    (.cost.total_lines_added // 0 | tostring),
    (.cost.total_lines_removed // 0 | tostring),
    (.version // ""),
    (.vim.mode // ""),
    (.rate_limits.five_hour.used_percentage | pct_or_neg1 | tostring),
    (.rate_limits.five_hour.resets_at | resets_min | tostring),
    (.rate_limits.seven_day.used_percentage | pct_or_neg1 | tostring),
    (.rate_limits.seven_day.resets_at | resets_min | tostring)
] | join("\u001f")') || _parsed=""

if [ -z "$_parsed" ]; then
    printf 'statusline: parse error\n' >&2
    exit 1
fi

_US=$(printf '\037')
IFS="$_US" read -r model used_pct total_input total_output cost_usd exceeds_200k project_dir duration_ms lines_added lines_removed cc_version vim_mode rate5h_pct rate5h_remaining_min rate7d_pct rate7d_remaining_min <<EOF
$_parsed
EOF

tokens_used=$(( total_input + total_output ))

# ── Git branch with 5-second cache ──────────────────────────────────────────
_git_cache="/tmp/claude-sl-git-$(id -u)"
git_branch=""
if [ -n "$project_dir" ] && [ -d "$project_dir" ]; then
    _cache_hit=0
    if [ -f "$_git_cache" ]; then
        _c_epoch=$(sed -n '1p' "$_git_cache")
        _c_dir=$(sed -n '2p' "$_git_cache")
        _c_branch=$(sed -n '3p' "$_git_cache")
        if [ "$(( _now - _c_epoch ))" -lt 5 ] && [ "$_c_dir" = "$project_dir" ]; then
            git_branch="$_c_branch"
            _cache_hit=1
        fi
    fi
    if [ "$_cache_hit" -eq 0 ]; then
        git_branch=$(git -C "$project_dir" --no-optional-locks symbolic-ref --short HEAD 2>/dev/null)
        printf '%s\n%s\n%s\n' "$_now" "$project_dir" "$git_branch" > "$_git_cache" 2>/dev/null
    fi
fi

# ── Project name ─────────────────────────────────────────────────────────────
if [ -n "$project_dir" ]; then
    project_name=$(basename "$project_dir")
else
    project_name=$(basename "$(pwd)")
fi

# ── Build progress bar (20 chars wide) ───────────────────────────────────────
if [ -n "$used_pct" ]; then
    pct_int=$(printf "%.0f" "$used_pct")
    filled=$(( pct_int * 20 / 100 ))
    empty=$(( 20 - filled ))

    filled_bar="" ; i=0
    while [ $i -lt $filled ]; do
        if [ "$_theme" = "none" ]; then filled_bar="${filled_bar}="; else filled_bar="${filled_bar}█"; fi
        i=$(( i + 1 ))
    done
    empty_bar="" ; i=0
    while [ $i -lt $empty ]; do
        if [ "$_theme" = "none" ]; then empty_bar="${empty_bar}."; else empty_bar="${empty_bar}░"; fi
        i=$(( i + 1 ))
    done

    if [ "$pct_int" -le 60 ]; then
        C_CTX="$C_CTX_OK"
    elif [ "$pct_int" -le 80 ]; then
        C_CTX="$C_CTX_WARN"
    else
        C_CTX="$C_CTX_BAD"
    fi
    pct_str="${pct_int}%"
else
    pct_int=0
    if [ "$_theme" = "none" ]; then
        filled_bar="" ; empty_bar="...................."
    else
        filled_bar="" ; empty_bar="░░░░░░░░░░░░░░░░░░░░"
    fi
    C_CTX="$C_CTX_OK"
    pct_str="0%"
fi

# ── Format tokens ────────────────────────────────────────────────────────────
if [ "$tokens_used" -ge 1000 ] 2>/dev/null; then
    tokens_str=$(awk -v n="$tokens_used" 'BEGIN { printf "%.1fk", n/1000 }')
else
    tokens_str="${tokens_used}"
fi

# ── Format cost ──────────────────────────────────────────────────────────────
# With config file: presence of 'cost' widget means show it.
# Without config file: honor CLAUDE_STATUSLINE_SHOW_COST env var.
cost_str=""
_show_cost_widget=0
if [ -f "$_conf" ]; then
    # Config exists — cost widget presence controls display
    _show_cost_widget=1
elif [ "${CLAUDE_STATUSLINE_SHOW_COST:-0}" = "1" ]; then
    _show_cost_widget=1
fi
if [ "$_show_cost_widget" = "1" ]; then
    if [ -n "$cost_usd" ] && [ "$cost_usd" != "0" ] && [ "$cost_usd" != "null" ]; then
        _cost_check=$(awk -v c="$cost_usd" 'BEGIN { print (c >= 0.005) ? 1 : 0 }')
        if [ "$_cost_check" -eq 1 ]; then
            cost_str=$(awk -v c="$cost_usd" 'BEGIN { printf "$%.2f", c }')
        fi
    fi
fi

# ── Format duration ──────────────────────────────────────────────────────────
duration_str=""
if [ -n "$duration_ms" ] && [ "$duration_ms" != "0" ] && [ "$duration_ms" != "null" ]; then
    _dur_sec=$(( duration_ms / 1000 ))
    _dur_h=$(( _dur_sec / 3600 ))
    _dur_m=$(( (_dur_sec % 3600) / 60 ))
    _dur_s=$(( _dur_sec % 60 ))
    if [ "$_dur_h" -gt 0 ]; then
        duration_str="${_dur_h}h${_dur_m}m"
    elif [ "$_dur_m" -gt 0 ]; then
        duration_str="${_dur_m}m${_dur_s}s"
    else
        duration_str="${_dur_s}s"
    fi
fi

# ── Format lines changed ────────────────────────────────────────────────────
lines_str=""
if [ -n "$lines_added" ] && [ -n "$lines_removed" ]; then
    if [ "$lines_added" != "0" ] || [ "$lines_removed" != "0" ]; then
        lines_str="+${lines_added}/-${lines_removed}"
    fi
fi

# ── Format version ───────────────────────────────────────────────────────────
version_str=""
if [ -n "$cc_version" ] && [ "$cc_version" != "null" ]; then
    version_str="v${cc_version}"
fi

# ── Rate limit helpers ──────────────────────────────────────────────────────
# Build a 5-dot bar: filled=● empty=○ (none theme: */.)
build_dots() {
    _bd_pct="$1"
    _bd_filled=$(( _bd_pct / 20 ))
    [ "$_bd_filled" -gt 5 ] && _bd_filled=5
    [ "$_bd_filled" -lt 0 ] && _bd_filled=0
    _bd_empty=$(( 5 - _bd_filled ))
    _bd_out=""
    _bd_i=0
    while [ "$_bd_i" -lt "$_bd_filled" ]; do
        if [ "$_theme" = "none" ]; then _bd_out="${_bd_out}*"; else _bd_out="${_bd_out}●"; fi
        _bd_i=$(( _bd_i + 1 ))
    done
    _bd_i=0
    while [ "$_bd_i" -lt "$_bd_empty" ]; do
        if [ "$_theme" = "none" ]; then _bd_out="${_bd_out}."; else _bd_out="${_bd_out}○"; fi
        _bd_i=$(( _bd_i + 1 ))
    done
    printf '%s' "$_bd_out"
}

# Format remaining minutes to human-readable: XdXh, XhYm, or Xm
fmt_remaining() {
    _fr_min="$1"
    case "$_fr_min" in ''|*[!0-9-]*) return 1 ;; esac
    [ "$_fr_min" -le 0 ] && return 1
    _fr_d=$(( _fr_min / 1440 ))
    _fr_h=$(( (_fr_min % 1440) / 60 ))
    _fr_m=$(( _fr_min % 60 ))
    if [ "$_fr_d" -gt 0 ]; then
        printf '%dd%dh' "$_fr_d" "$_fr_h"
    elif [ "$_fr_h" -gt 0 ]; then
        printf '%dh%dm' "$_fr_h" "$_fr_m"
    else
        printf '%dm' "$_fr_m"
    fi
}

# Render a single rate sub-widget: label + dots + pct + time
# Returns 1 if data is absent (-1).
_render_rate() {
    _rr_label="$1"; _rr_pct_raw="$2"; _rr_remain="$3"
    case "$_rr_pct_raw" in ''|-1) return 1 ;; esac
    _rr_pct=$(LC_ALL=C printf "%.0f" "$_rr_pct_raw")
    [ "$_rr_pct" -gt 100 ] && _rr_pct=100
    if [ "$_rr_pct" -ge 100 ]; then
        _rr_c="$C_ALERT"; _rr_suffix="!"
    elif [ "$_rr_pct" -gt 80 ]; then
        _rr_c="$C_CTX_BAD"; _rr_suffix=""
    elif [ "$_rr_pct" -gt 60 ]; then
        _rr_c="$C_CTX_WARN"; _rr_suffix=""
    else
        _rr_c="$C_CTX_OK"; _rr_suffix=""
    fi
    _rr_dots=$(build_dots "$_rr_pct")
    _rr_time=""
    if _rr_time_str=$(fmt_remaining "$_rr_remain"); then
        _rr_time=" $_rr_time_str"
    fi
    printf '%b' "${_rr_c}${_rr_label} ${_rr_dots} ${_rr_pct}%${_rr_suffix}${_rr_time}${C_RESET}"
}

# ── Render widget ────────────────────────────────────────────────────────────
render_widget() {
    case "$1" in
        model)    printf '%b' "${C_MODEL}${model}${C_RESET}" ;;
        bar)      printf '%b' "[${C_BAR_FILL}${filled_bar}${C_BAR_EMPTY}${empty_bar}${C_RESET}]" ;;
        ctx)      printf '%b' "${C_CTX}${pct_str}${C_RESET}" ;;
        tokens)   printf '%b' "${C_TOKENS}${tokens_str} tokens${C_RESET}" ;;
        cost)     [ -n "$cost_str" ] && printf '%b' "${C_COST}${cost_str}${C_RESET}" || return 1 ;;
        duration) [ -n "$duration_str" ] && printf '%b' "${C_COST}${duration_str}${C_RESET}" || return 1 ;;
        lines)    [ -n "$lines_str" ] && printf '%b' "${C_TOKENS}${lines_str}${C_RESET}" || return 1 ;;
        alert)    [ "$exceeds_200k" = "true" ] && printf '%b' "${C_ALERT}⚠ 200k${C_RESET}" || return 1 ;;
        git)      [ -n "$git_branch" ] && printf '%b' "${C_BRANCH} ${git_branch}${C_RESET}" || return 1 ;;
        project)  printf '%b' "${C_PROJECT}${project_name}${C_RESET}" ;;
        version)  [ -n "$version_str" ] && printf '%b' "${C_SEP}${version_str}${C_RESET}" || return 1 ;;
        vim)
            case "$vim_mode" in
                INSERT*) printf '%b' "${C_ALERT}[INSERT]${C_RESET}" ;;
                NORMAL*) printf '%b' "${C_CTX_OK}[NORMAL]${C_RESET}" ;;
                VISUAL*) printf '%b' "${C_CTX_WARN}[VISUAL]${C_RESET}" ;;
                ?*)      printf '%b' "${C_SEP}[${vim_mode}]${C_RESET}" ;;
                *)       return 1 ;;
            esac
            ;;
        rate5h)
            _render_rate "5h" "$rate5h_pct" "$rate5h_remaining_min" || return 1
            ;;
        rate7d)
            _render_rate "7d" "$rate7d_pct" "$rate7d_remaining_min" || return 1
            ;;
        rate)
            _rate_has_output=0
            if [ "$rate5h_pct" != "-1" ] && [ -n "$rate5h_pct" ]; then
                if _render_rate "5h" "$rate5h_pct" "$rate5h_remaining_min"; then
                    _rate_has_output=1
                fi
            fi
            if [ "$rate7d_pct" != "-1" ] && [ -n "$rate7d_pct" ]; then
                [ "$_rate_has_output" -eq 1 ] && printf '  '
                if _render_rate "7d" "$rate7d_pct" "$rate7d_remaining_min"; then
                    _rate_has_output=1
                fi
            fi
            [ "$_rate_has_output" -eq 0 ] && return 1
            ;;
        *) return 1 ;;
    esac
}

# ── Render a line of widgets ─────────────────────────────────────────────────
render_line() {
    _render_sep=0
    for _w in $1; do
        # Skip widgets with no data
        case "$_w" in
            cost)     [ -z "$cost_str" ] && continue ;;
            duration) [ -z "$duration_str" ] && continue ;;
            lines)    [ -z "$lines_str" ] && continue ;;
            alert)    [ "$exceeds_200k" != "true" ] && continue ;;
            git)      [ -z "$git_branch" ] && continue ;;
            version)  [ -z "$version_str" ] && continue ;;
            vim)      [ -z "$vim_mode" ] && continue ;;
            rate5h)   { [ "$rate5h_pct" = "-1" ] || [ -z "$rate5h_pct" ]; } && continue ;;
            rate7d)   { [ "$rate7d_pct" = "-1" ] || [ -z "$rate7d_pct" ]; } && continue ;;
            rate)     { [ "$rate5h_pct" = "-1" ] || [ -z "$rate5h_pct" ]; } && { [ "$rate7d_pct" = "-1" ] || [ -z "$rate7d_pct" ]; } && continue ;;
        esac
        [ "$_render_sep" -eq 1 ] && printf '%b' "$SEP"
        render_widget "$_w"
        _render_sep=1
    done
    printf '\n'
}

# ── Output ───────────────────────────────────────────────────────────────────
render_line "$_widgets_l1"
if [ -n "${_widgets_l2## }" ]; then
    render_line "$_widgets_l2"
fi

# ── Write session state for tmux/dashboard ────────────────────────────────────
SESSIONS_DIR="$HOME/.claude/sessions"
if [ -d "$SESSIONS_DIR" ]; then
    _epoch="$_now"
    _activity=$(printf '%s' "$input" | jq -r '.last_message // .session.last_message // ""' 2>/dev/null) || _activity=""
    _mem=$(ps -o rss= -p "$_claude_pid" 2>/dev/null | awk '{printf "%d",$1+0}') || _mem=0
    _sf="$SESSIONS_DIR/$_claude_pid.json"
    _status=""
    read -r _status _ < "$SESSIONS_DIR/$_claude_pid.status" 2>/dev/null || _status=""
    if [ -z "$_status" ]; then
        _status=$(printf '%s' "$input" | jq -r '.session.status // .status // ""' 2>/dev/null) || _status=""
    fi
    if [ -z "$_status" ] || [ "$_status" = "null" ]; then
        _prev_tout=0
        if [ -f "$_sf" ]; then
            _prev_tout=$(jq -r '.tokens_out // 0' "$_sf" 2>/dev/null) || _prev_tout=0
        fi
        if [ "${total_output:-0}" -gt "$_prev_tout" ] 2>/dev/null; then
            _status="working"
        else
            _status="idle"
        fi
    fi
    jq -n \
        --arg pid    "$_claude_pid" \
        --arg epoch  "$_epoch" \
        --arg model  "${model:-}" \
        --arg pdir   "${project_dir:-}" \
        --arg pname  "${project_name:-}" \
        --arg branch "${git_branch:-}" \
        --arg status "${_status:-}" \
        --arg act    "${_activity:-}" \
        --arg pct    "${pct_int:-0}" \
        --arg tin    "${total_input:-0}" \
        --arg tout   "${total_output:-0}" \
        --arg mem    "${_mem:-0}" \
        --arg cost   "${cost_usd:-0}" \
        '{pid:($pid|tonumber),epoch:($epoch|tonumber),model:$model,
          project_dir:$pdir,project_name:$pname,git_branch:$branch,
          status:$status,last_activity:$act,
          used_pct:($pct|tonumber),tokens_in:($tin|tonumber),
          tokens_out:($tout|tonumber),mem_kb:($mem|tonumber),
          cost_usd:($cost|tonumber)}' \
        > "$_sf" 2>/dev/null || true
fi
